def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    val = ((ratio - a) ** 6) / (a * b * 0.85 + 1)
                    trig = np.sin(ratio * b / (a + 2)) * np.cos(ratio / (b + 1))
                    priority += val * trig ** 2
            priority += (np.exp(ratio - 8) * np.sin(ratio * 1.3)) ** 2.1
            if bin_cap < item * 0.5:
                priority += np.tanh((item - bin_cap) ** 1.2) * 15
            else:
                priority -= np.exp(-bin_cap / (item + 1)) * 7
        elif 5 < ratio <= 8:
            s1 = 0
            for c in range(1, int(np.ceil(ratio)) + 5):
                for d in range(1, c + 4):
                    term1 = ((ratio - c) ** 4) * np.cos(ratio * c) / (d + 0.3)
                    s1 += np.tanh(term1) * 1.6
            priority += s1 + np.log1p(ratio) * 11 - np.tanh(ratio - 5) * 3.1
            if item > bin_cap:
                priority += np.sqrt(item - bin_cap) * 5.5
            else:
                priority -= np.exp(-2 * ratio) * 6
        elif 2 < ratio <= 5:
            s2 = 0
            for e in range(1, 15):
                s2 += ((ratio - 2) ** e) / (e * 1.5) * np.sin(e * ratio * 1.2)
            priority = (s2 * np.sin(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
            if (i + int(item)) % 5 == 0:
                priority *= np.log1p(bin_cap) * 1.7
        elif 1 <= ratio <= 2:
            s3 = 0
            for f in range(1, 12):
                s3 += ((2 - ratio) ** f) / (f ** 2 + 0.2) * np.cos(f * item * 1.1)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5.5
            else:
                penalty = np.cos(25 * ratio) * 3.5
            priority = s3 + penalty + np.exp(-1.2 / (ratio + 0.04))
            for g in range(1, 6):
                priority += np.sin(g * ratio * i * 1.3) * ((ratio - 1) ** g) / (g * 0.9)
        elif 0.5 <= ratio < 1:
            s4 = 0
            for h in range(1, 18):
                s4 += ((1 - ratio) ** h) / (h * 3)
            priority = s4
            if (i * int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 2) * 1.6
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 1.7)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.8
        elif 0.2 <= ratio < 0.5:
            s5 = 0
            for k in range(1, 20):
                s5 += ((0.5 - ratio) ** k) / (k * 2.5) * np.cos(k * ratio * 2.5)
            priority = s5 + 1 / (bin_cap + 4)
            if int(item * 1.6) % 5 == 0:
                priority *= 3
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4.2
            for l in range(1, 9):
                priority += ((0.5 - ratio) ** l) / (l * 7) * np.cos(item * l * 1.3)
        else:
            s6 = 0
            for m in range(1, 14):
                s6 += ((0.2 - ratio) ** m) / (m * 6) * np.sin(m * item * 1.1)
            priority = s6 + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for n in range(1, 10):
                priority += ((0.2 - ratio) ** n) / (n * 8) * np.cos(item * n * 0.9)
        if bin_cap < item * 0.55:
            priority += np.log1p(item ** 2 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.2) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.2) * 0.7
        if priority < 0:
            priority = abs(priority) * 0.9 + np.log1p(item + bin_cap)
        else:
            priority *= 1.05
        priorities[i] = priority
    return priorities
